request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?message ?messageId ?messageName ?initiatingTask ?initiatingParticipant ?fromTaskId ?toTaskId WHERE {
  ?model a bboExt:Model ;
         tai:originalId ?origId ;
         tai:normalizedId ?normId ;
         tai:belongsTo ?org .
  FILTER(?origId = "2aa476e4bbdf451083ec316570f7a3be" || ?normId = "2aa476e4bbdf451083ec316570f7a3be")
  ?message tai:belongsTo ?choreo .

  ?message a bboExt:Message ;
           tai:belongsTo ?choreo .
  OPTIONAL { ?message bbo:id ?messageId . }
  OPTIONAL { ?message bbo:name ?messageName . }

  OPTIONAL {
    ?mf a bboExt:MessageFlow ;
        bboExt:messageRef ?messageRef ;
        tai:belongsTo ?choreo .
    FILTER(STR(?messageRef) = COALESCE(?messageId, STRAFTER(STR(?message), "#")))
    OPTIONAL {
      ?sourceTask tai:belongsTo ?choreo .
      ?sourceTask a bboExt:ChoreographyTask .
      ?sourceTask bbo:id ?fromTaskId .
      FILTER(STRENDS(STR(?sourceTask), ?fromTaskId))
    }
    OPTIONAL {
      ?mf bboExt:sourceRef ?srcRef .
      FILTER(STR(?messageRef) = STR(?srcRef) || true)
    }
    OPTIONAL {
      ?targetTask tai:belongsTo ?choreo .
      ?targetTask a bboExt:ChoreographyTask .
      ?targetTask bbo:id ?toTaskId .
    }
  }

  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          bboExt:initiatingParticipantRef ?initiatingParticipantRef ;
          tai:belongsTo ?choreo .
    FILTER(STRENDS(STR(?initiatingParticipant), ?initiatingParticipantRef))
  }

  OPTIONAL {
    ?initTask a bboExt:ChoreographyTask ;
              tai:belongsTo ?choreo ;
              bboExt:initiatingParticipantRef ?partRef .
    FILTER(BOUND(?partRef))
    BIND(?initTask AS ?initiatingTask)
  }
}
LIMIT 25
